import { sql } from "drizzle-orm";
import {
  boolean,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
} from "drizzle-orm/pg-core";

import type { Recipient } from "@/lib/schemas/email";
import type {
  ExpenseEmailAttachmentRef,
  ExpenseEmailRecipientStatus,
  ExpenseEmailSendStatus,
} from "@/lib/schemas/expense-email";

import { user } from "./auth-schema";

/**
 * better-auth tables (`user`, `session`, `account`, `verification`),
 * generated by `pnpm dlx @better-auth/cli@latest generate --output
 * src/db/auth-schema.ts`. Re-exported here so `drizzle-kit` picks them up
 * for migrations and `src/lib/auth.ts`'s `drizzleAdapter` sees them via this
 * same barrel's `schema` import. Do not hand-edit `auth-schema.ts` — re-run
 * the CLI (e.g. after enabling a plugin) to regenerate it.
 */
export * from "./auth-schema";

/**
 * Consortiums — top-level entity owned by an authenticated user (`ownerId`).
 * Soft-deleted rows keep `isDeleted = true` and are excluded from list/detail.
 */
export const consortiums = pgTable(
  "consortiums",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    name: text("name").notNull(),
    location: text("location").notNull(),
    paymentAlias: text("payment_alias"),
    billingEmail: text("billing_email"),
    driveLink: text("drive_link"),
    amount: integer("amount").notNull().default(0),
    ownerId: text("owner_id")
      .notNull()
      .references(() => user.id),
    isDeleted: boolean("is_deleted").notNull().default(false),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => [
    index("consortiums_owner_id_active_idx")
      .on(table.ownerId)
      .where(sql`${table.isDeleted} = false`),
  ],
);

export type ConsortiumRow = typeof consortiums.$inferSelect;
export type NewConsortium = typeof consortiums.$inferInsert;

// --- Domain tables ---
// Add new domain tables (e.g. units, owners, expenses) below, each
// as its own exported `pgTable(...)` with its inferred `$inferSelect` /
// `$inferInsert` types, following the `consortiums` table above as the
// reference pattern.

/**
 * Tenant emails — contact emails for functional units within a consortium.
 * Unit identity is denormalized (`floor` / `departmentNumber` / `letter`);
 * soft-deleted rows keep `isDeleted = true` and are excluded from list queries.
 */
export const tenantEmails = pgTable(
  "tenant_emails",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    consortiumId: uuid("consortium_id")
      .notNull()
      .references(() => consortiums.id),
    /** Floor label, e.g. "1" or "PB". */
    floor: text("floor"),
    departmentNumber: text("department_number"),
    letter: text("letter"),
    email: text("email").notNull(),
    /** Contact role: "propietario" | "inquilino". */
    contactType: text("contact_type").notNull().$type<"propietario" | "inquilino">(),
    isDeleted: boolean("is_deleted").notNull().default(false),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => [
    index("tenant_emails_consortium_id_active_idx")
      .on(table.consortiumId)
      .where(sql`${table.isDeleted} = false`),
  ],
);

export type TenantEmailRow = typeof tenantEmails.$inferSelect;
export type NewTenantEmail = typeof tenantEmails.$inferInsert;

/**
 * Email log - one row per email send attempt (single email or batch),
 * recording who sent it, to whom, and the outcome reported by Resend.
 */
export const emailLog = pgTable(
  "email_log",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    subject: text("subject").notNull(),
    body: text("body").notNull(),
    /** Recipients this email was sent to. */
    recipients: jsonb("recipients").notNull().$type<Recipient[]>(),
    recipientCount: integer("recipient_count").notNull(),
    /** Outcome reported by Resend, e.g. "sent", "partial", or "failed". */
    status: text("status").notNull(),
    /** Resend message ids returned for each successfully sent email. */
    resendIds: jsonb("resend_ids").$type<string[]>(),
    error: text("error"),
    sentByUserId: text("sent_by_user_id").references(() => user.id),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => [index("email_log_created_at_idx").on(table.createdAt)],
);

export type EmailLog = typeof emailLog.$inferSelect;
export type NewEmailLog = typeof emailLog.$inferInsert;

/**
 * Expense email send — one monthly-expense fan-out job for a consortium.
 * Attachment binaries live in Supabase Storage; only path/metadata refs here.
 * Independent from `email_log` (notifications / comments).
 */
export const expenseEmailSends = pgTable(
  "expense_email_sends",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    consortiumId: uuid("consortium_id")
      .notNull()
      .references(() => consortiums.id),
    /**
     * Per-consortium sequential display id (starts at 1). Assigned only on the
     * first successful create insert — not on upload or retryPending.
     */
    sendNumber: integer("send_number").notNull(),
    subject: text("subject").notNull(),
    body: text("body").notNull(),
    linkUrl: text("link_url"),
    /** Job lifecycle: queued → sending → sent | partial | failed. */
    status: text("status").notNull().$type<ExpenseEmailSendStatus>().default("queued"),
    /** PDF refs in Storage: `[{ storagePath, filename, sizeBytes }]`.
     * `storagePath` = `expense-emails/{consortiumId}/{sendId}/{file}` (logical);
     * object key in bucket omits the bucket-name prefix. */
    attachmentRefs: jsonb("attachment_refs").notNull().$type<ExpenseEmailAttachmentRef[]>(),
    sentByUserId: text("sent_by_user_id").references(() => user.id),
    /** Opaque runner lease token; only the current token may persist outcomes. */
    claimToken: uuid("claim_token"),
    /** Lease expiry used to reclaim a runner interrupted by a timeout or crash. */
    claimExpiresAt: timestamp("claim_expires_at", { withTimezone: true }),
    recipientCount: integer("recipient_count").notNull().default(0),
    sentCount: integer("sent_count").notNull().default(0),
    failedCount: integer("failed_count").notNull().default(0),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
    finishedAt: timestamp("finished_at", { withTimezone: true }),
  },
  (table) => [
    index("expense_email_sends_consortium_id_created_at_idx").on(
      table.consortiumId,
      table.createdAt,
    ),
    uniqueIndex("expense_email_sends_consortium_id_send_number_unique").on(
      table.consortiumId,
      table.sendNumber,
    ),
  ],
);

export type ExpenseEmailSendRow = typeof expenseEmailSends.$inferSelect;
export type NewExpenseEmailSend = typeof expenseEmailSends.$inferInsert;

/**
 * Expense email recipient — one row per address in an expense send job.
 * No display name column: the email template uses a fixed greeting.
 */
export const expenseEmailRecipients = pgTable(
  "expense_email_recipients",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    sendId: uuid("send_id")
      .notNull()
      .references(() => expenseEmailSends.id),
    email: text("email").notNull(),
    /** Per-recipient outcome: pending | sent | failed. */
    status: text("status").notNull().$type<ExpenseEmailRecipientStatus>().default("pending"),
    /** Resend message id when the provider accepted the send. */
    resendId: text("resend_id"),
    error: text("error"),
    attempts: integer("attempts").notNull().default(0),
    lastAttemptAt: timestamp("last_attempt_at", { withTimezone: true }),
  },
  (table) => [
    index("expense_email_recipients_send_id_idx").on(table.sendId),
    index("expense_email_recipients_send_id_status_idx").on(table.sendId, table.status),
  ],
);

export type ExpenseEmailRecipientRow = typeof expenseEmailRecipients.$inferSelect;
export type NewExpenseEmailRecipient = typeof expenseEmailRecipients.$inferInsert;

/** Curated consortium action-history event types (v1 taxonomy). */
export type ConsortiumActivityType =
  | "expense_sent"
  | "notification_sent"
  | "drive_link_updated"
  | "consortium_updated"
  | "amount_updated";

/**
 * Optional metadata for a history row. Shape varies by `type`; only the
 * fields relevant to that event are populated.
 */
export interface ConsortiumActivityPayload {
  sendId?: string;
  sendNumber?: number;
  recipientCount?: number;
  subject?: string;
  messagePreview?: string;
  previousDriveLink?: string | null;
  newDriveLink?: string | null;
  fieldsChanged?: string[];
  previousAmount?: number;
  newAmount?: number;
}

/**
 * Consortium activities — curated action history for the consortium detail feed.
 * One row per user-visible action (anti-saturation: one save → one event).
 */
export const consortiumActivities = pgTable(
  "consortium_activities",
  {
    id: uuid("id")
      .primaryKey()
      .default(sql`gen_random_uuid()`),
    consortiumId: uuid("consortium_id")
      .notNull()
      .references(() => consortiums.id),
    actorUserId: text("actor_user_id").references(() => user.id),
    /** Event taxonomy, e.g. "expense_sent" or "drive_link_updated". */
    type: text("type").notNull().$type<ConsortiumActivityType>(),
    /** Spanish user-facing summary stored at write time. */
    summary: text("summary").notNull(),
    payload: jsonb("payload")
      .notNull()
      .$type<ConsortiumActivityPayload>()
      .default(sql`'{}'::jsonb`),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => [
    index("consortium_activities_consortium_id_created_at_idx").on(
      table.consortiumId,
      table.createdAt,
    ),
  ],
);

export type ConsortiumActivityRow = typeof consortiumActivities.$inferSelect;
export type NewConsortiumActivity = typeof consortiumActivities.$inferInsert;
